
getgenv().UpdatePlrData = function(AddPlayerData)
    local success = pcall(function()
        local placeId = game.PlaceId
        
        if placeId == 3823781113 or placeId == 96522925012827 then
            local playerGui = game.Players.LocalPlayer.PlayerGui
            if playerGui then
                local mainGui = playerGui:FindFirstChild("MainGui")
                if mainGui then
                    local startFrame = mainGui:FindFirstChild("StartFrame")
                    if startFrame then
                        local currency = startFrame:FindFirstChild("Currency")
                        if currency then
                            local diamonds = currency:FindFirstChild("Diamonds")
                            if diamonds then
                                local amount = diamonds:FindFirstChild("Amount")
                                if amount and amount.Text then
                                    AddPlayerData("Diamond 💎", amount.Text)
                                end
                            end
                        end
                    end
                end
            end
        end
    end)
    return success
end






















